1	interface Item {
2	  type: string;
3	}
4	
5	interface Step {
6	  type: string;
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  steps: Step[];
12	}
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_INSURANCE_RATE = 0.1;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	function calculateBasePremium(items: Item[]): number {
31	  const typeCounts: Record<string, number> = {};
32	  for (const item of items) {
33	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
34	  }
35	
36	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
37	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
38	      ? BLOCK_PREMIUM
39	      : count * BASE_PREMIUM[type];
40	    return total + premium;
41	  }, 0);
42	}
43	
44	export function processScenario(scenario: Scenario): unknown {
45	  const items = scenario.steps[0].items;
46	  const basePremium = calculateBasePremium(items);
47	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
48	  const premium = Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
49	
50	  return [{ premium }];
51	}
