  const scenario = {
    customer: { yearsWithMHPCO: 0, quoteNumber: 1 },
    steps: [{ type: "quote", items: [
      { type: "rune" }, { type: "rune" }, { type: "rune" },
      { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
